// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/wait-for-azure-runbook-job-completed/result`);
  const configBody = await configGet.json();
  const status = (configBody?.properties?.status || configBody?.status || configBody?.jobStatus || '''''''').toUpperCase();
  console.log(status);

  if (status !== 'COMPLETED') {
    throw new Error(`Azure Automation runbook failed with status: ${status}`);
  }

  return configBody;
}
